const msg=($input.first().json.chatInput||$input.first().json.input||'').trim();
const num=msg.replace(/\s/g,'').toUpperCase();
const isNum=/^(SC|NI|OC|SO|NP|NV)?[0-9]{6,8}$/.test(num);
if(isNum)return[{json:{mode:'single',chUrl:'https://api.company-information.service.gov.uk/company/'+num,max:1,location:'',sicCodes:[]}}];
const sics=(msg.match(/\b\d{4,5}\b/g)||[]).filter(s=>+s>=1000);
const mx=(msg.match(/\b(\d+)\s*comp/i)||[])[1];
const max=Math.min(mx?+mx:25,25);
const loc=msg.replace(/\b\d{4,5}\b/g,'').replace(/\b\d+\s*comp\w*/gi,'').replace(/sic/gi,'').replace(/[,\s]+/g,' ').trim();
const u=new URL('https://api.company-information.service.gov.uk/advanced-search/companies');
if(sics.length)u.searchParams.set('sic_codes',sics.join(','));
if(loc)u.searchParams.set('location',loc);
u.searchParams.set('company_status','active');
u.searchParams.set('items_per_page',String(max));
return[{json:{mode:'sic',chUrl:u.toString(),sicCodes:sics,location:loc,max}}];

const src=$('Parse Input').first().json;
const d=$input.first().json;
const addr=o=>[o?.address_line_1,o?.locality,o?.postal_code].filter(Boolean).join(', ');
let list=[];
if(src.mode==='single'){
  if(d.company_number)list=[{companyNumber:d.company_number,companyName:d.company_name||'',address:addr(d.registered_office_address),sicCodes:d.sic_codes||[],incorporated:d.date_of_creation||''}];
}else{
  list=(d.items||[]).map(c=>({companyNumber:c.company_number,companyName:c.company_name||'',address:addr(c.registered_office_address),sicCodes:c.sic_codes||[],incorporated:c.date_of_creation||''}));
}
return list.slice(0,src.max||25).map(c=>({json:c}));

return $input.all().map((item,i)=>{
  const co=$('Normalize Results').all()[i].json;
  const dirs=(item.json.items||[]).filter(o=>!o.resigned_on).map(o=>o.name+' ('+o.officer_role+')').slice(0,3);
  return{json:{...co,directors:dirs.join('; ')||'N/A'}};
});

return $input.all().map((item,i)=>{
  const co=$('Add Officers').all()[i].json;
  const f=(item.json.items||[])[0];
  const pdfUrl=f?.links?.document_metadata?f.links.document_metadata+'/content':null;
  return{json:{...co,pdfUrl,filingDate:f?.date||null,filingType:f?.type||null}};
});

return $input.all().map((item,i)=>{
  const co=$('Add Filing URL').all()[i].json;
  const txt=item.json.error?'':(item.json.text||item.json.data||'');
  return{json:{...co,pdfText:String(txt).substring(0,2000)}};
});

return $input.all().map((item,i)=>{
  const co=$('Merge PDF').all()[i].json;
  const web=(item.json.results||[]).slice(0,3).map(r=>r.title+': '+(r.content||'')).join('
');
  const prompt='Assess this UK company as a Portland Fuel B2B prospect. Return JSON only.

COMPANY: '+co.companyName+'
NO: '+co.companyNumber+'
ADDRESS: '+co.address+'
SIC: '+(co.sicCodes||[]).join(',')+'
FOUNDED: '+co.incorporated+'
DIRECTORS: '+co.directors+'
ACCOUNTS: '+co.filingDate+' ('+co.filingType+')

ACCOUNTS TEXT:
'+(co.pdfText||'Not available')+'

WEB:
'+(web||'No results')+'

PRODUCTS:
1.Fuel Cards (3+ vehicle fleets)
2.Bulk Delivery (farms,construction,fixed sites)
3.Bunker Networks (road freight,multi-site)
4.Fuel Hedging (large businesses,fuel as major cost)
5.Fuel Consultancy (complex procurement)

Return: {"score":1-10,"products":["product names"],"summary":"2 sentences","size":"micro/small/medium/large","approach":"who to contact and angle","flags":"red flags or none"}';
  const body=JSON.stringify({model:'qwen3.6:27b',prompt,stream:false,format:'json'});
  return{json:{...co,webSnippets:web,ollamaBody:body}};
});

const src=$('Parse Input').first().json;
const leads=$input.all().map(i=>i.json).sort((a,b)=>b.aiScore-a.aiScore).filter(c=>c.aiScore>=5);
if(!leads.length)return[{json:{subject:'Portland Fuel Leads — No qualified results',htmlBody:'<p>No companies scored 5 or above for: '+(src.location||src.chUrl||'')+'</p>'}}];
const col=s=>s>=8?'#27ae60':s>=6?'#e67e22':'#e74c3c';
const rows=leads.map(c=>'<tr><td style="padding:10px;border-bottom:1px solid #ddd"><strong><a href="https://find-and-update.company-information.service.gov.uk/company/'+c.companyNumber+'">'+c.companyName+'</a></strong><br><small>'+c.address+'</small><br><small>Directors: '+c.directors+'</small></td><td style="padding:10px;border-bottom:1px solid #ddd;text-align:center"><span style="font-size:22px;font-weight:bold;color:'+col(c.aiScore)+'">'+c.aiScore+'</span></td><td style="padding:10px;border-bottom:1px solid #ddd">'+c.aiProducts.join(', ')+'</td><td style="padding:10px;border-bottom:1px solid #ddd">'+c.aiSummary+'<br><em>'+c.aiApproach+'</em>'+(c.aiFlags&&c.aiFlags!=='none'?'<br><b style="color:red">'+c.aiFlags+'</b>':'')+'</td></tr>').join('');
const date=new Date().toLocaleDateString('en-GB');
const subj='Portland Fuel Leads — '+leads.length+' leads | '+(src.location||'Company lookup')+' | '+date;
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:950px;margin:0 auto"><h2 style="color:#2c3e50">Portland Fuel Lead Digest</h2><p><b>'+leads.length+' qualified leads</b> | '+(src.location||'')+' | SIC: '+(src.sicCodes||[]).join(', ')+' | '+date+'</p><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse"><thead><tr style="background:#2c3e50;color:#fff"><th style="padding:10px;text-align:left">Company</th><th style="padding:10px;width:60px">Score</th><th style="padding:10px;width:180px">Products</th><th style="padding:10px;text-align:left">Assessment</th></tr></thead><tbody>'+rows+'</tbody></table><p style="color:#999;font-size:11px">Generated '+new Date().toISOString()+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];
